                val typeIdx = cursor.getColumnIndex("account_type")
                while (cursor.moveToNext()) {
                    val name = cursor.getString(nameIdx)
                    val type = cursor.getString(typeIdx)
                    if (!name.isNullOrEmpty() && !type.isNullOrEmpty()) {
